const body = $input.first().json.body ?? $input.first().json;
const id       = body?.id       ?? null;
const text     = (body?.text    ?? '').trim();
const color    = body?.color    ?? 'yellow';
const createdBy = body?.created_by ?? null;
const actions  = Array.isArray(body?.actions)  ? body.actions  : [];
const redirects = Array.isArray(body?.redirects) ? body.redirects : [];

if (!text) throw new Error('Campo text es requerido');
if (!id && !createdBy) throw new Error('Campo created_by es requerido al crear');

return [{ json: { id, text, color, created_by: createdBy, actions, redirects, is_new: !id } }];
